var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"수, 숨 넘어가겠네......","JPN":"も、もう無理……","ENG":"I-I can barely breathe...","TWN":"喘、喘死我了……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"잠깐 쉬죠. 여기라면 쉽게 쫓아오지 못할 거예요.","JPN":"少し休みましょう。ここなら簡単には追って来れないはずです。","ENG":"Let's take a break. They can't follow us this far away so quickly.","TWN":"我們歇一下吧，她們應該不能馬上追上來。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"메이드가 대체 총질을 왜 저렇게 잘해?! 뭔가 이상하잖아?!","JPN":"メイドなのになんで銃の扱いが上手いわけ！？　おかしすぎるでしょ！？","ENG":"How come those maids are so good at shooting? Does that make sense to you?","TWN":"女僕什麼時候會射擊了？！妳不覺得很奇怪嗎？！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그러려니 하세요. 저희 사장님은 로봇인데요, 뭘.","JPN":"あり得るんじゃないですか？　私たちの社長なんかロボットですからね。","ENG":"It doesn't, but then again, our boss is a robot.","TWN":"算了，我們老闆還是機器人呢。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"일단 상황 설명을 해 주세요. 어떻게 된 일이죠?","JPN":"ひとまず状況を説明してください。どういうことですか？","ENG":"Please explain the situation. What happened?","TWN":"這到底是什麼情況？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"처음에는 머릿수에서 밀려도 엄폐물을 활용해서 제법 잘 버티고 있었어.","JPN":"最初は数的不利でも遮蔽物なり活用して、なんとか耐えられたんだけど……","ENG":"At first, we did a good job stalling the victims by using the structures around us to make up for our inferior numbers.","TWN":"剛開始雖然我們人少，但利用掩蔽物撐了下去。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"하지만 중간부터 사장님이 방어도 하지 않고 적극적으로 공격해 오더라고.","JPN":"途中から社長が防御もせずに、一方的に攻撃を仕掛けてきたのよ。","ENG":"But halfway through the fight, the Boss started attacking aggressively without bothering to defend himself.","TWN":"但是突然，老闆不再防禦，反而積極進攻。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"메이드 아가씨들은 차마 주인님을 공격할 수가 없어서 결국......","JPN":"メイドのお嬢ちゃんたちは、ご主人様を攻撃することができずに結局……","ENG":"The maid ladies couldn't bring themselves to attack their master, so...","TWN":"女僕小姐們又不敢攻擊自己的主人，所以就……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"말도 안 돼!","JPN":"あり得ない！","ENG":"This is ridiculous!","TWN":"怎麼會！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이 주시윤이란 녀석이 범인 아니었어?","JPN":"このアキヤマ・シリュウってやつが、犯人じゃなかったの？","ENG":"I thought this guy, Shiyoon, was the perpetrator.","TWN":"難道兇手不是周時雲嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"범인을 잡았는데 희생자가 더 생길 리 없잖아?!","JPN":"犯人を捕まえたのに、犠牲者が増えるはずないじゃない！","ENG":"And there shouldn't have been more victims now that he's with us.","TWN":"我們都抓到兇手了，怎麼還會有人中招。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"혹은 선배가 범인이 아니었다거나 말이죠.","JPN":"もしくは先輩が犯人じゃなかったってことですね。","ENG":"Or, maybe he's not the perpetrator.","TWN":"也許前輩並不是兇手。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"えっ……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"잠시만요. 확인해 봐야겠어요.","JPN":"ちょっと待ってください。確認した方が良さそうです。","ENG":"Give me a moment. Let me check something.","TWN":"稍等，我需要確認一下。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......역시, 예상대로네요.","JPN":"……やっぱり、予想通りですね。","ENG":"It's just as I thought.","TWN":"……果然不出所料。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"자, 선배의 이마를 보세요.","JPN":"ほら、先輩の額を見てください。","ENG":"Here, take a look at his forehead.","TWN":"妳們看前輩的額頭。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"저건......?","JPN":"あれは……？","ENG":"That's...","TWN":"這是……？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"사냥감의 낙인이잖아! 이 녀석도 희생자였다는 거야?!","JPN":"獲物の烙印！？　こいつも犠牲者だってこと？","ENG":"The mark of prey! He was just another victim?","TWN":"獵物的印記！這傢伙居然也是受害者？！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"네. 머리칼에 가려져 있어서 확인하지 못했던 거에요.","JPN":"はい。今までは髪の毛に隠れて確認できなかったのです。","ENG":"Yes. We didn't see the mark because his hair covered it.","TWN":"是的，因為被頭髮擋住了，所以沒有看到。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"범인에 의해 꼭두각시처럼 움직이던 걸 우리가 멋대로 착각했을 뿐이죠.","JPN":"犯人に操られていたのを、私たちが勝手に誤解してしまったようです。","ENG":"He was just a puppet. We barked up the wrong tree.","TWN":"他其實只是兇手的傀儡，是我們搞錯了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"말도 안 돼...... 그럼 범인은 누구란 거야?","JPN":"そんな……じゃあ、犯人は誰？","ENG":"I can't believe this. Then, who's the perpetrator?","TWN":"怎麼會……那兇手到底是誰？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"너, 혹시 처음부터 이 녀석이 범인이 아니라는 걸 알고 있었어?","JPN":"アンタ、ひょっとして最初からこいつが犯人じゃないって知ってたの？","ENG":"Did you know from the beginning that this guy wasn't the perpetrator?","TWN":"難道妳一開始就知道這個傢伙不是兇手？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"어느 정도는요.","JPN":"まぁ、ある程度は。","ENG":"To an extent, yes.","TWN":"我也是猜測。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"실비아 씨, 제가 전투 직전에 전자기 펄스를 펼쳐 달라고 했던 말 기억하세요?","JPN":"シルビアさん、私が戦闘直前に電磁パルスを張ってほしいと言ったのを覚えていますか？","ENG":"Sylvia, remember I asked you to cover the area with an EMP before the fight?","TWN":"希爾維亞，妳還記得剛剛我請妳展開電磁脈衝嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"당연히 기억하지.","JPN":"もちろん、覚えてるわ。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그러고 보니 왜 부탁했던 거야? 이 녀석이 사이보그도 아닌데?","JPN":"そういえば、なんであんなことを？　こいつはサイボーグじゃないのに？","ENG":"Speaking of which, why did you ask? This guy isn't a cyborg.","TWN":"妳怎麼突然讓我那麼做？這傢伙也不是個機器人。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"이유는 간단해요. 만약 선배가 희생자라면 범인에게 조종당하고 있었겠죠.","JPN":"理由は簡単です。もし先輩が犠牲者なら犯人に操られていたはずです。","ENG":"The reason is simple. I thought if he was a victim, he had to be controlled by the perpetrator.","TWN":"理由很簡單，如果前輩是受害者，那麼肯定就是被兇手操控的。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그렇다면 어떤 방식으로든 선배와 범인이 연결되어 있어야 해요.","JPN":"ということは、何かしらの方法で犯人と先輩が繋がっているということになります。","ENG":"And in order to be controlled, he had to be connected to the culprit somehow.","TWN":"那麼兇手不管用什麼方式，必須和前輩連接起來。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"전 그 연결을 강제로 끊어버리게 한 거죠.","JPN":"私はその繋がりを切断しようと思ったんです。","ENG":"That's why we needed the EMP to disrupt their connection.","TWN":"而我強制斷掉了那個連接。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"통하지 않았다면 모르겠는데...... 실비아 씨도 직접 눈으로 보셨잖아요?","JPN":"それが通じなければ違ったということになりますが……シルビアさんも見てましたよね？","ENG":"And it worked. You saw it too, didn't you Sylvia?","TWN":"這個辦法行不通也就算了……不過，希爾維亞妳不也看到了嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"확실히...... 전자기 펄스를 펼친 다음부터 눈에 띄게 느려졌어.","JPN":"確かに……電磁パルスを張ってから、動きがすごく遅くなってた。","ENG":"You're right. He definitely slowed down after I used the EMP.","TWN":"確實……展開電磁脈衝後，他明顯變慢了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"네. 그래서 우리가 이길 수 있었고요.","JPN":"はい、だから私たちは勝てたのです。","ENG":"Yes, and that was why we won.","TWN":"是的，所以我們才能打贏他。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"결국 헛다리만 짚고 원점으로 돌아왔단 소리네.","JPN":"結局、見当違いで原点に戻っちゃったってことね。","ENG":"So, we're back to square one. Again.","TWN":"結果我們還是搞錯了，這下又回到了原點。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그럼 대체 범인이 누구야? 애초에 그런 게 있기나 한 거야?","JPN":"じゃあ、犯人は誰？　元々そんなのいるの？","ENG":"Then, who's the perpetrator? Does it even exist?","TWN":"那到底誰是兇手？還是一開始就沒有兇手？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"시작은 추리물이었잖아요. 범인 없이는 엔딩도 없겠죠.","JPN":"始まりは推理でした。犯人なしにエンディングは訪れません。","ENG":"This whole thing began as a mystery. It's got to have a main perpetrator to have an ending.","TWN":"一個推理電影，沒有兇手就沒有結尾了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"따라잡히기 전에 서두르죠. 두 사람 다 저를 따라오세요!","JPN":"追いつかれる前に急ぎましょう。二人とも私について来てください！","ENG":"Let's hurry before they catch up with us. Both of you, follow me!","TWN":"趁還沒有被發現趕緊走吧，妳們倆跟我來！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"subtitle","speaker":null,"text":{"KOREA":"일곱 번째 희생자: <color=#ffd34c>주시윤</color>","JPN":"七人目の犠牲者：<color=#ffd34c>アキヤマ・シリュウ</color>","ENG":"Victim 7: <color=#ffd34c>Joo Shiyoon</color>","TWN":"第七個犧牲者：<color=#ffd34c>周時雲</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"subtitle","speaker":null,"text":{"KOREA":"남은 생존자: <color=#ffd34c>3명</color>","JPN":"残りの生存者：<color=#ffd34c>3人</color>","ENG":"Remaining survivors: <color=#ffd34c>3</color>","TWN":"生存者：<color=#ffd34c>3名</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};